$(function(){$("#ayswitcher").on("change",function(){var t=$("option:selected",this),n=t.val();console.log(n);console.log(baseApiUrl);$.ajax({url:baseApiUrl+"AYSwitch/"+n,method:"POST",dataType:"TEXT"}).done(function(n){n=="OK"&&location.reload()}).fail(function(n,t,i){alert("Communication error: "+i)})})});